// Pseudocode for thread creation using pthreads
THREAD_FUNCTION threadFunction(void* arg) {
    int threadId = *(int*)arg;
    PRINT "Thread " + threadId + " starting"
    // Thread work here
    FOR i = 1 to 1000:
        // computation
    END FOR
    PRINT "Thread " + threadId + " finished"
    RETURN 0
}

MAIN() {
    pthread_t threads[5];
    int threadArgs[5]

    // Create 5 threads
    FOR i = 0 to 4:
        threadArgs[i] = i
        pthread_create(&threads[i], NULL, threadFunction, &threadArgs[i])
    END FOR

    // Wait for all threads to complete
    FOR i = 0 to 4:
        pthread_join(threads[i], NULL)
    END FOR

    PRINT "All threads completed"
}

#include <pthread.h>
#include <stdio.h>

// Shared variable
int sharedCounter = 0;

// Mutex for protecting shared variable
pthread_mutex_t mutex = PTHREAD_MUTEX_INITIALIZER;

void* incrementCounter(void* arg) {
    int threadNum = *(int*)arg;

    for (int i = 0; i < 100000; i++) {
        // Lock mutex before accessing shared resource
        pthread_mutex_lock(&mutex);

        // Critical section - only one thread can be here
        sharedCounter++;

        // Unlock mutex after critical section
        pthread_mutex_unlock(&mutex);
    }

    printf("Thread %d finished\n", threadNum);
    return NULL;
}

int main() {
    pthread_t threads[4];
    int args[4] = {1, 2, 3, 4};

    // Create 4 threads
    for (int i = 0; i < 4; i++) {
        pthread_create(&threads[i], NULL, incrementCounter, &args[i]);
    }

    // Wait for completion
    for (int i = 0; i < 4; i++) {
        pthread_join(threads[i], NULL);
    }

    printf("Final counter value: %d (expected: 400000)\n", sharedCounter);

    return 0;
}

// Shared resources
BUFFER[10]  // Circular buffer of size 10
int in = 0   // Producer inserts here
int out = 0  // Consumer removes from here

// Semaphores
SEMAPHORE mutex = 1      // Mutual exclusion for buffer
SEMAPHORE empty = 10     // Count of empty slots
SEMAPHORE full = 0       // Count of filled slots

PROCEDURE producer(item) {
    // Wait for empty slot
    WAIT(empty)

    // Enter critical section
    WAIT(mutex)

    // Add item to buffer
    BUFFER[in] = item
    in = (in + 1) MOD 10

    // Exit critical section
    SIGNAL(mutex)

    // Signal that an item is available
    SIGNAL(full)
}

PROCEDURE consumer() {
    // Wait for available item
    WAIT(full)

    // Enter critical section
    WAIT(mutex)

    // Remove item from buffer
    item = BUFFER[out]
    out = (out + 1) MOD 10

    // Exit critical section
    SIGNAL(mutex)

    // Signal that a slot is empty
    SIGNAL(empty)

    RETURN item
}
